// ─── APM & CO2 CONSTANTS (da co2-calculator.js) ───────────────────────────────
const APM_C  = 25700;   // secondi attenzione cinema per 1.000 admissions
const APM_D  = 5700;    // secondi attenzione digital per 1.000 admissions
const TREE   = 21.77;   // kg CO2 assorbiti da un albero/anno (EPA)
const GRID   = 0.270;   // kg CO2 per kWh (ISPRA 2024)
const KWH_CIRCUIT = 4.1;
const KWH_FILM    = 5.5;

const calcAPM    = (adm) => Math.round((adm / 1000) * APM_C);
const calcCO2    = (type, spots, spotSec) => {
  const kwh = type==="film" ? KWH_FILM : KWH_CIRCUIT;
  const adH = (spots * spotSec) / 3600;
  return adH * kwh * GRID;
};
const calcDigCO2 = (adm) => (adm / 1000) * 0.668;
