// ─── AI ASSISTANT ─────────────────────────────────────────────────────────────
// ─── BACKUP MODAL ─────────────────────────────────────────────────────────────
function BackupModal({ mode, json, onJsonChange, onImport, msg, onClose }) {
  const [copied, setCopied] = useState(false);
  const copyToClipboard = () => {
    try {
      navigator.clipboard.writeText(json).then(()=>{ setCopied(true); setTimeout(()=>setCopied(false),2000); });
    } catch { setCopied(false); }
  };
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.7)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ ...s.card, width:"100%", maxWidth:640, display:"flex", flexDirection:"column", gap:16, padding:28 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <h2 style={{ margin:0, fontSize:18, fontWeight:800, color:C.bright, fontFamily:"Georgia,serif" }}>
            {mode==="export" ? "⬇️ Esporta Backup" : "⬆️ Ripristina Backup"}
          </h2>
          <button onClick={onClose} style={{ background:"none", border:"none", color:C.muted, cursor:"pointer", fontSize:20, lineHeight:1 }}>✕</button>
        </div>
        {mode==="export" && (
          <p style={{ margin:0, fontSize:12, color:C.sub }}>
            Copia tutto il testo qui sotto e salvalo in un file di testo, email o note. Incollalo nella schermata di ripristino per recuperare i dati.
          </p>
        )}
        {mode==="import" && (
          <p style={{ margin:0, fontSize:12, color:C.sub }}>
            Incolla il testo del backup copiato in precedenza, poi clicca <strong style={{color:C.gold}}>Ripristina</strong>.
          </p>
        )}
        <textarea
          value={json}
          readOnly={mode==="export"}
          onChange={mode==="import" ? e=>onJsonChange(e.target.value) : undefined}
          placeholder={mode==="import" ? 'Incolla qui il JSON del backup...' : ''}
          style={{ width:"100%", height:280, background:C.bg, border:`1px solid ${C.border2}`, borderRadius:8, color:C.text, fontFamily:"monospace", fontSize:11, padding:12, resize:"vertical", boxSizing:"border-box" }}
        />
        {msg && (
          <div style={{ background: msg.startsWith("✅") ? `${C.green}18` : `${C.red}18`, border:`1px solid ${msg.startsWith("✅")?C.green:C.red}44`, borderRadius:8, padding:"10px 14px", color: msg.startsWith("✅") ? C.green : C.red, fontSize:12 }}>
            {msg}
          </div>
        )}
        <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
          <Btn variant="ghost" small onClick={onClose}>Chiudi</Btn>
          {mode==="export" && (
            <Btn onClick={copyToClipboard}>{copied ? "✅ Copiato!" : "📋 Copia tutto"}</Btn>
          )}
          {mode==="import" && (
            <Btn onClick={()=>onImport(json)} disabled={!json.trim()}>⬆️ Ripristina</Btn>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [loginError,  setLoginError]  = useState("");
  const [users,       setUsers]       = useState(DEMO_USERS);
  const [clients,     setClients]     = useState(DEMO_CLIENTS);
  const [campaigns,   setCampaigns]   = useState(DEMO_CAMPAIGNS);
  const [circuitData, setCircuitData] = useState(BUILTIN_CIRCUIT);
  const [circuitDef,  setCircuitDef]  = useState(null); // cinema list from geo file
  const [profileData, setProfileData] = useState({}); // Cinexpert audience profiles by key

  const [adminTab,    setAdminTab]    = useState("clients");
  const [view,        setView]        = useState("list");
  const [selClient,   setSelClient]   = useState(null);
  const [selCamp,     setSelCamp]     = useState(null);
  const [showClientForm,   setShowClientForm]   = useState(false);
  const [showCampaignForm, setShowCampaignForm] = useState(false);
  const [editingCamp, setEditingCamp] = useState(null);

  const apiSet = dbSet;
  const apiGet = dbGet;
  const save = useCallback((key, data) => { dbSet(key, data); }, []);

  useEffect(()=>{
    (async()=>{
      const su = await apiGet("mm_users_v2");   if(su) setUsers(su);
      const sc = await apiGet("mm_clients_v2"); if(sc) setClients(sc);
      const sp = await apiGet("mm_camps_v2");   if(sp) setCampaigns(sp);
      const sd = await apiGet("mm_circuit_v2");
      if (sd) {
        const cleaned = Object.fromEntries(Object.entries(sd).filter(([,v]) => v.source !== "built-in"));
        setCircuitData(cleaned);
        if (Object.keys(cleaned).length !== Object.keys(sd).length) apiSet("mm_circuit_v2", cleaned);
      }
      const sg = await apiGet("mm_circuit_def"); if(sg) setCircuitDef(sg);
      const sp2 = await apiGet("mm_profile_v1"); if(sp2) setProfileData(sp2);
    })();
  }, []);

  const handleCircuitDef = (def) => {
    setCircuitDef(def);
    apiSet("mm_circuit_def", def);
  };

  const handleLogin = (username, password) => {
    const u = users.find(u=>u.username===username && u.password===password);
    if (!u) { setLoginError("Credenziali non valide."); return; }
    setLoginError(""); setCurrentUser(u);
    if (u.role==="viewer") {
      const cl = clients.find(c=>c.id===u.clientId);
      if (cl) { setSelClient(cl); setView("campaigns"); }
    }
  };
  const handleLogout = () => { setCurrentUser(null); setView("list"); setSelClient(null); setSelCamp(null); setAdminTab("clients"); };

  const isSuperAdmin = currentUser?.role==="superadmin";
  const isAdmin  = currentUser?.role==="admin" || isSuperAdmin;
  const isViewer = currentUser?.role==="viewer";

  const addClient = (cl, newUser) => {
    const nextClients=[...clients,cl]; setClients(nextClients); save("mm_clients_v2",nextClients);
    const nc={...campaigns,[cl.id]:[]}; setCampaigns(nc); save("mm_camps_v2",nc);
    if (newUser) { const nextUsers=[...users,newUser]; setUsers(nextUsers); save("mm_users_v2",nextUsers); }
    setShowClientForm(false);
  };

  const deleteClient = (id) => {
    const nextClients=clients.filter(c=>c.id!==id); setClients(nextClients); save("mm_clients_v2",nextClients);
    const nc={...campaigns}; delete nc[id]; setCampaigns(nc); save("mm_camps_v2",nc);
    // remove associated viewer users
    const nextUsers=users.filter(u=>u.clientId!==id); setUsers(nextUsers); save("mm_users_v2",nextUsers);
  };

  const saveCampaign = (camp) => {
    const cid=selClient.id; const exist=campaigns[cid]||[]; const idx=exist.findIndex(c=>c.id===camp.id);
    const updated = idx>=0 ? exist.map(c=>c.id===camp.id?camp:c) : [...exist,camp];
    const nc={...campaigns,[cid]:updated}; setCampaigns(nc); save("mm_camps_v2",nc);
    setShowCampaignForm(false); setEditingCamp(null);
  };

  const addUser    = (u) => { const next=[...users,u]; setUsers(next); save("mm_users_v2",next); };
  const editUser   = (u) => { const next=users.map(x=>x.id===u.id?u:x); setUsers(next); save("mm_users_v2",next); };
  const deleteUser = (id)=> { const next=users.filter(u=>u.id!==id); setUsers(next); save("mm_users_v2",next); };

  const [backupModal, setBackupModal] = useState(null); // null | "export" | "import"
  const [backupJson,  setBackupJson]  = useState("");
  const [backupMsg,   setBackupMsg]   = useState("");

  const handleExportBackup = () => {
    const backup = {
      version: "mm-backup-v1",
      exportedAt: new Date().toISOString(),
      users, clients, campaigns, circuitData, circuitDef,
    };
    setBackupJson(JSON.stringify(backup, null, 2));
    setBackupMsg("");
    setBackupModal("export");
  };

  const handleImportBackup = () => {
    setBackupJson("");
    setBackupMsg("");
    setBackupModal("import");
  };

  const handleImportBackupText = (text) => {
    try {
      const b = JSON.parse(text);
      if (b.version !== "mm-backup-v1") { setBackupMsg("❌ File backup non valido (versione errata)."); return; }
      if (b.users)       { setUsers(b.users);             save("mm_users_v2", b.users); }
      if (b.clients)     { setClients(b.clients);         save("mm_clients_v2", b.clients); }
      if (b.campaigns)   { setCampaigns(b.campaigns);     save("mm_camps_v2", b.campaigns); }
      if (b.circuitData) { setCircuitData(b.circuitData); save("mm_circuit_v2", b.circuitData); }
      if (b.circuitDef)  { setCircuitDef(b.circuitDef);   save("mm_circuit_def", b.circuitDef); }
      setBackupMsg("✅ Backup ripristinato con successo!");
      setTimeout(() => setBackupModal(null), 1500);
    } catch(err) { setBackupMsg("❌ JSON non valido: " + err.message); }
  };

  const handleImportProfile = (data) => {
    setProfileData(prev => {
      const nc = { ...prev, [data.key]: data };
      save("mm_profile_v1", nc);
      return nc;
    });
  };

  const handleImport = (data) => {
    const nc={...circuitData,[data.key]:data}; setCircuitData(nc); save("mm_circuit_v2",nc);
  };

  const handleDeletePeriod = (key) => {
    const nc={...circuitData}; delete nc[key]; setCircuitData(nc); save("mm_circuit_v2",nc);
  };

  if (!currentUser) return <LoginScreen onLogin={handleLogin} error={loginError} />;

  const viewerClient = isViewer ? clients.find(c=>c.id===currentUser.clientId) : null;

  return (
    <div style={{ minHeight:"100vh", background:C.bg, color:C.text, fontFamily:"'Trebuchet MS',sans-serif" }}>
      {isAdmin && (
        <>
          <AdminNav active={adminTab} onNav={(t)=>{ setAdminTab(t); setView("list"); setSelClient(null); setSelCamp(null); }} user={currentUser} onLogout={handleLogout} />
          {adminTab==="users" && (
            <UsersScreen users={users} clients={clients} campaigns={campaigns} currentUser={currentUser} onAdd={addUser} onEdit={editUser} onDelete={deleteUser} onExportBackup={handleExportBackup} onImportBackup={handleImportBackup} />
          )}
          {adminTab==="import" && (
            <ImportScreen circuitData={circuitData} onImport={handleImport} onDeletePeriod={handleDeletePeriod} circuitDef={circuitDef} onCircuitDef={handleCircuitDef} profileData={profileData} onImportProfile={handleImportProfile} />
          )}
          {adminTab==="agenzie" && (
            <AgenzieScreen clients={clients} campaigns={campaigns} circuitData={circuitData}
              onSelectCampaign={(clientId, campId) => {
                const cl = clients.find(c=>c.id===clientId);
                const camp = (campaigns[clientId]||[]).find(c=>c.id===campId);
                if (cl && camp) { setSelClient(cl); setSelCamp(camp); setAdminTab("clients"); setView("dashboard"); }
              }} />
          )}
          {adminTab==="clients" && (
            <>
              {view==="list" && <ClientList clients={clients} campaigns={campaigns} circuitData={circuitData} onSelect={c=>{setSelClient(c); setView("campaigns");}} onNew={()=>setShowClientForm(true)} onDelete={deleteClient} />}
              {view==="campaigns" && selClient && (
                <CampaignList client={selClient} campaigns={campaigns[selClient.id]||[]} circuitData={circuitData} isViewer={false}
                  onSelect={c=>{setSelCamp(c); setView("dashboard");}}
                  onNew={()=>setShowCampaignForm(true)}
                  onEdit={c=>{setEditingCamp(c); setShowCampaignForm(true);}}
                  onBack={()=>{setSelClient(null); setView("list");}} />
              )}
              {view==="dashboard" && selCamp && (
                <CampaignDashboard campaign={selCamp} clientName={selClient?.name} circuitData={circuitData} circuitDef={circuitDef} profileData={profileData} isViewer={false} onBack={()=>{setSelCamp(null); setView("campaigns");}} />
              )}
            </>
          )}
        </>
      )}
      {isViewer && viewerClient && (
        <>
          <div style={{ background:C.surface, borderBottom:`1px solid ${C.border}`, padding:"12px 36px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              <span style={{ fontSize:16 }}>🎬</span>
              <span style={{ fontSize:12, fontWeight:800, color:C.gold, fontFamily:"Georgia,serif" }}>Moviemedia</span>
              <span style={{ color:C.border2, margin:"0 4px" }}>·</span>
              <span style={{ fontSize:12, color:C.sub }}>{viewerClient.name}</span>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:12 }}>
              <span style={{ fontSize:11, color:C.sub }}>{currentUser.name}</span>
              <Btn small variant="ghost" onClick={handleLogout}>Esci</Btn>
            </div>
          </div>
          {view==="campaigns" && (
            <CampaignList client={viewerClient} campaigns={campaigns[viewerClient.id]||[]} circuitData={circuitData} isViewer={true}
              onSelect={c=>{setSelCamp(c); setView("dashboard");}}
              onNew={null} onEdit={null} onBack={null} />
          )}
          {view==="dashboard" && selCamp && (
            <CampaignDashboard campaign={selCamp} clientName={viewerClient.name} circuitData={circuitData} circuitDef={circuitDef} profileData={profileData} isViewer={true} onBack={()=>{setSelCamp(null); setView("campaigns");}} />
          )}
        </>
      )}
      {showClientForm   && <ClientForm onSave={addClient} onClose={()=>setShowClientForm(false)} />}
      {showCampaignForm && selClient && (
        <CampaignForm clientName={selClient.name} circuitData={circuitData} initial={editingCamp}
          onSave={saveCampaign} onClose={()=>{setShowCampaignForm(false); setEditingCamp(null);}} />
      )}
      {backupModal && (
        <BackupModal
          mode={backupModal}
          json={backupJson}
          onJsonChange={setBackupJson}
          onImport={handleImportBackupText}
          msg={backupMsg}
          onClose={()=>setBackupModal(null)}
        />
      )}

    </div>
  );
}
